import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// ─── Nav config per role ──────────────────────────────────────────────────────
const NAV = {
  admin: [
    { to: '/admin',               label: 'Dashboard',    icon: '⊞' },
    { to: '/admin/users',         label: 'All Users',    icon: '👤' },
    { to: '/admin/communities',   label: 'Communities',  icon: '🏛️' },
    { to: '/admin/events',        label: 'Events',       icon: '📅' },
    { to: '/clubs',               label: 'Public Portal',icon: '🌐', external: true },
  ],
  community_admin: [
    { to: '/community-admin',         label: 'Dashboard',   icon: '⊞' },
    { to: '/community-admin/members', label: 'Members',     icon: '👥' },
    { to: '/community-admin/events',  label: 'Events',      icon: '📅' },
    { to: '/community-admin/profile', label: 'Community',   icon: '🏛️' },
    { to: '/clubs',                   label: 'Public Portal',icon: '🌐', external: true },
  ],
};

const ROLE_LABEL = {
  admin: 'System Admin',
  community_admin: 'Community Admin',
};

const ROLE_COLOR = {
  admin: 'var(--pink-accent)',
  community_admin: 'var(--purple-light)',
};

// ─── Component ────────────────────────────────────────────────────────────────
export default function DashboardLayout({ children }) {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  const navItems = NAV[user?.role] || [];

  const handleLogout = () => { logout(); navigate('/'); };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', paddingTop: 68 }}>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div
          onClick={() => setMobileOpen(false)}
          style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.6)', zIndex: 200 }}
        />
      )}

      {/* ── Sidebar ── */}
      <aside style={{
        position: 'fixed',
        top: 68,
        left: 0,
        bottom: 0,
        width: collapsed ? 64 : 220,
        background: 'var(--bg-secondary)',
        borderRight: '1px solid var(--border)',
        zIndex: 201,
        transition: 'width 0.25s cubic-bezier(0.4,0,0.2,1)',
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
      }}>

        {/* Collapse toggle */}
        <button
          onClick={() => setCollapsed(c => !c)}
          style={{
            background: 'none', border: 'none', cursor: 'pointer',
            padding: '14px 20px', color: 'var(--text-muted)',
            display: 'flex', alignItems: 'center', justifyContent: collapsed ? 'center' : 'flex-end',
            fontSize: '0.75rem', transition: 'all 0.2s',
            borderBottom: '1px solid var(--border)',
          }}
          title={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        >
          {collapsed ? '›' : '‹'}
        </button>

        {/* Role badge */}
        {!collapsed && (
          <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border)' }}>
            <div style={{
              fontSize: '0.65rem', fontWeight: 700, textTransform: 'uppercase',
              letterSpacing: '0.1em', color: ROLE_COLOR[user?.role], marginBottom: 4,
            }}>
              {ROLE_LABEL[user?.role]}
            </div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {user?.name}
            </div>
            {user?.role === 'community_admin' && user?.managedCommunity && (
              <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: 2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                {user.managedCommunity.name}
              </div>
            )}
          </div>
        )}

        {/* Nav Items */}
        <nav style={{ flex: 1, padding: '12px 0', overflowY: 'auto' }}>
          {navItems.map(item => (
            <NavLink
              key={item.to}
              to={item.to}
              end={item.to === '/admin' || item.to === '/community-admin'}
              style={({ isActive }) => ({
                display: 'flex',
                alignItems: 'center',
                gap: 12,
                padding: collapsed ? '12px 0' : '11px 20px',
                justifyContent: collapsed ? 'center' : 'flex-start',
                color: isActive ? 'white' : 'var(--text-secondary)',
                textDecoration: 'none',
                fontSize: '0.85rem',
                fontWeight: isActive ? 700 : 500,
                background: isActive ? 'rgba(124,58,237,0.15)' : 'transparent',
                borderLeft: isActive ? '3px solid var(--purple-primary)' : '3px solid transparent',
                transition: 'all 0.2s',
                letterSpacing: '0.02em',
                position: 'relative',
              })}
            >
              <span style={{ fontSize: '1rem', flexShrink: 0 }}>{item.icon}</span>
              {!collapsed && (
                <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                  {item.label}
                </span>
              )}
              {collapsed && (
                <span style={{
                  position: 'absolute', left: '110%', background: 'var(--bg-card)',
                  border: '1px solid var(--border)', borderRadius: 'var(--radius-sm)',
                  padding: '4px 10px', fontSize: '0.78rem', color: 'white',
                  whiteSpace: 'nowrap', zIndex: 300, pointerEvents: 'none',
                  opacity: 0,
                }} className="sidebar-tooltip">
                  {item.label}
                </span>
              )}
            </NavLink>
          ))}
        </nav>

        {/* Logout */}
        <div style={{ padding: '12px 0', borderTop: '1px solid var(--border)' }}>
          <button
            onClick={handleLogout}
            style={{
              display: 'flex', alignItems: 'center', gap: 12,
              padding: collapsed ? '11px 0' : '11px 20px',
              justifyContent: collapsed ? 'center' : 'flex-start',
              width: '100%', background: 'none', border: 'none',
              cursor: 'pointer', color: 'var(--danger)',
              fontSize: '0.85rem', fontWeight: 500,
              transition: 'all 0.2s',
            }}
          >
            <span style={{ fontSize: '1rem' }}>⏻</span>
            {!collapsed && <span>Sign Out</span>}
          </button>
        </div>
      </aside>

      {/* ── Main content ── */}
      <main style={{
        flex: 1,
        marginLeft: collapsed ? 64 : 220,
        transition: 'margin-left 0.25s cubic-bezier(0.4,0,0.2,1)',
        minWidth: 0,
      }}>
        {children}
      </main>

      <style>{`
        @media (max-width: 768px) {
          aside { width: 220px !important; transform: ${mobileOpen ? 'translateX(0)' : 'translateX(-100%)'}; }
          main  { margin-left: 0 !important; }
        }
      `}</style>
    </div>
  );
}
